DROP TABLE IF EXISTS "public"."invoice_items";
CREATE TABLE "public"."invoice_items" (
  "id" int4 NOT NULL DEFAULT nextval('invoice_items_id_seq'::regclass),
  "invoice_id" int4 NOT NULL,
